public class IncrementDemo {
    public static void main(String[] args) {
        int a = 5;
        int b = 5;

        // Post-increment: use the value, then increment
        int postResult = a++;
        System.out.println("Post-increment result: " + postResult);
        System.out.println("a after a++: " + a);

        // Pre-increment: increment first, then use the value
        int preResult = ++b;
        System.out.println("Pre-increment result: " + preResult);
        System.out.println("b after ++b: " + b);
    }
}
